import{_ as a,o as s,c as e,a5 as l}from"./chunks/framework.B5tqjWbr.js";const k=JSON.parse('{"title":"概念：单相 PFC 的 PWM/ADC 时序与控制延迟","description":"","frontmatter":{"date":"2026-06-21T00:00:00.000Z","category":"电源控制","source":"power","visibility":"public","title":"概念：单相 PFC 的 PWM/ADC 时序与控制延迟","tags":["power-electronics"],"status":"learning","summary":"功率因数校正（power factor correction / PFC）电流环不是“采样后立刻作用于功率级”。模数转换器（analog-to-digital converter / ADC）采样、控制计算、脉宽调制（pulse-width modulation / PWM）寄存器更新之间存在控制延迟（control "},"headers":[],"relativePath":"content/power/concepts/power-electronics/single-phase-pfc-pwm-delay.md","filePath":"content/power/concepts/power-electronics/single-phase-pfc-pwm-delay.md","lastUpdated":null}'),t={name:"content/power/concepts/power-electronics/single-phase-pfc-pwm-delay.md"};function p(n,i,o,h,r,d){return s(),e("div",null,[...i[0]||(i[0]=[l(`<h1 id="概念-单相-pfc-的-pwm-adc-时序与控制延迟" tabindex="-1">概念：单相 PFC 的 PWM/ADC 时序与控制延迟 <a class="header-anchor" href="#概念-单相-pfc-的-pwm-adc-时序与控制延迟" aria-label="Permalink to &quot;概念：单相 PFC 的 PWM/ADC 时序与控制延迟&quot;">​</a></h1><h2 id="_1-它是什么" tabindex="-1">1. 它是什么 <a class="header-anchor" href="#_1-它是什么" aria-label="Permalink to &quot;1. 它是什么&quot;">​</a></h2><p>功率因数校正（power factor correction / PFC）电流环不是“采样后立刻作用于功率级”。模数转换器（analog-to-digital converter / ADC）采样、控制计算、脉宽调制（pulse-width modulation / PWM）寄存器更新之间存在控制延迟（control delay）。</p><p>本节只讲采样点（sampling point）、PWM 更新点和延迟如何影响电流跟踪，不展开完整开关级模型。</p><p>本节不包含公司内部代码、未公开产品方案、客户项目参数或内部测试数据。维护本学习仓库时，不能记录公司内部代码、未公开产品方案、客户项目参数、内部测试数据。</p><h2 id="_2-ups-为什么需要它" tabindex="-1">2. UPS 为什么需要它 <a class="header-anchor" href="#_2-ups-为什么需要它" aria-label="Permalink to &quot;2. UPS 为什么需要它&quot;">​</a></h2><p>不间断电源（uninterruptible power supply / UPS）里的 PFC 电流环通常运行很快。即使算法公式正确，如果采样点靠近开关噪声、PWM 更新晚一个或几个周期，实际电流也会落后参考，导致：</p><ul><li>电流跟踪误差变大。</li><li>占空比补偿滞后。</li><li>高频噪声和采样抖动进入控制环。</li><li>电流环稳定裕度变差。</li></ul><h2 id="_3-物理直觉" tabindex="-1">3. 物理直觉 <a class="header-anchor" href="#_3-物理直觉" aria-label="Permalink to &quot;3. 物理直觉&quot;">​</a></h2><p>控制延迟像开车时后视镜画面延迟。你看到的是稍早的状态，打方向盘作用到车辆也要一段时间。延迟越大，越容易修正过头或跟不上目标。</p><h2 id="_4-数学形式" tabindex="-1">4. 数学形式 <a class="header-anchor" href="#_4-数学形式" aria-label="Permalink to &quot;4. 数学形式&quot;">​</a></h2><p>理想无延迟：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>u[k] = controller(i_ref[k] - iL[k])</span></span></code></pre></div><p>有延迟时，可以近似写成：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>u[k] = controller(i_ref[k - N] - iL[k - N])</span></span>
<span class="line"><span>delay_time = N * Ts</span></span></code></pre></div><p>其中 <code>N</code> 是延迟的控制周期数，<code>Ts</code> 是控制周期。</p><h2 id="_5-一个仿真任务与仿真观察" tabindex="-1">5. 一个仿真任务与仿真观察 <a class="header-anchor" href="#_5-一个仿真任务与仿真观察" aria-label="Permalink to &quot;5. 一个仿真任务与仿真观察&quot;">​</a></h2><p>运行：</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python simulations\\python\\single_phase_pfc_pwm_delay.py</span></span></code></pre></div><p>对比一个仿真任务：</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python simulations\\python\\single_phase_pfc_pwm_delay.py </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">delay</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">samples </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> --</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">output simulations\\results\\pfc_pwm_delay_0.png </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">no</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">open</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python simulations\\python\\single_phase_pfc_pwm_delay.py </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">delay</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">samples </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">5</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> --</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">output simulations\\results\\pfc_pwm_delay_5.png </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">no</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">open</span></span></code></pre></div><p>观察：</p><ul><li>电流参考 <code>iref</code> 与含延迟的实际电流 <code>iL</code> 是否有相位差。</li><li>跟踪误差是否随延迟增大而变大。</li><li>ADC 采样点和 PWM 更新点是否清楚标出。</li><li>参数框中的延迟样本数和微秒数。</li></ul><h2 id="_6-固件落地" tabindex="-1">6. 固件落地 <a class="header-anchor" href="#_6-固件落地" aria-label="Permalink to &quot;6. 固件落地&quot;">​</a></h2><p>真实固件中，相关问题通常出现在：</p><ul><li>ADC 触发时刻是否避开开关边沿。</li><li>ADC 转换完成中断和控制 ISR 的先后关系。</li><li>PWM 比较寄存器是立即更新还是在周期边界影子加载。</li><li>控制计算是否跨周期生效。</li></ul><p>读代码时要沿着“PWM 触发 ADC -&gt; ADC 完成 -&gt; ISR 计算 -&gt; PWM 更新”追踪。</p><h2 id="_7-常见误解" tabindex="-1">7. 常见误解 <a class="header-anchor" href="#_7-常见误解" aria-label="Permalink to &quot;7. 常见误解&quot;">​</a></h2><ul><li><p>错误理解：控制公式对了，时序不重要。<br> 正确理解：数字电源控制里，采样和更新时序直接影响相位裕度。</p></li><li><p>错误理解：采样越靠近边沿越及时。<br> 正确理解：边沿附近开关噪声大，采样可能更差。</p></li><li><p>错误理解：延迟只影响高频细节。<br> 正确理解：延迟会表现成相位滞后，电流环带宽越高越敏感。</p></li></ul><h2 id="_8-验收标准" tabindex="-1">8. 验收标准 <a class="header-anchor" href="#_8-验收标准" aria-label="Permalink to &quot;8. 验收标准&quot;">​</a></h2><ul><li>能解释 ADC 采样点、ISR 计算、PWM 更新点之间的先后关系。</li><li>能把延迟样本数换算成微秒。</li><li>能在图中指出 <code>iref</code>、含延迟 <code>iL</code>、误差、ADC 采样点和 PWM 更新点。</li><li>能解释为什么延迟会增大跟踪误差。</li><li>能基于 <code>single_phase_pfc_pwm_delay.py</code> 的仿真图准备具体导师问题。</li></ul><h2 id="_9-复盘问题" tabindex="-1">9. 复盘问题 <a class="header-anchor" href="#_9-复盘问题" aria-label="Permalink to &quot;9. 复盘问题&quot;">​</a></h2><ul><li>默认仿真中，延迟是几个控制周期？对应多少微秒？</li><li>把 <code>--delay-samples</code> 从 0 改到 5 后，RMS tracking error 如何变化？</li><li>如果真实工程使用 PWM 影子寄存器，控制输出通常什么时候生效？</li></ul><h2 id="_10-导师问题" tabindex="-1">10. 导师问题 <a class="header-anchor" href="#_10-导师问题" aria-label="Permalink to &quot;10. 导师问题&quot;">​</a></h2><ul><li>我用 <code>single_phase_pfc_pwm_delay.py</code> 看到 3 个控制周期延迟会增大 RMS 跟踪误差。公司 PFC 电流环从 ADC 采样到 PWM 生效通常有几个周期延迟？</li><li>图中标出了 ADC 采样点和 PWM 更新点。公司平台一般在 PWM 周期的哪个位置触发 ADC 采样？</li><li>PWM 比较寄存器是立即更新还是影子寄存器周期边界更新？这对控制延迟怎么算？</li></ul>`,35)])])}const u=a(t,[["render",p]]);export{k as __pageData,u as default};
